import React, { useState, useEffect, useMemo } from 'react';

/**
 * ПОРТФОЛИО АЛЕКСАНДРЫ — ВОССТАНОВЛЕНИЕ ВИЗУАЛА
 * Здесь принудительно прописаны:
 * 1. ГЛАССМОРФИЗМ (blur backdrop)
 * 2. ПРАВИЛЬНЫЕ ШРИФТЫ (Playfair & Inter)
 * 3. ГРАДИЕНТЫ И РАЗМЕРЫ
 */

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];

  const projects = useMemo(() => [
    { id: '01', title: "Ethereal Identity", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=1200" },
    { id: '02', title: "Nexus Interface", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=1200" },
    { id: '03', title: "Vanguard Logo", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=1200" },
    { id: '04', title: "Mono Print", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1561070791-2526d30994b5?auto=format&fit=crop&q=80&w=1200" },
  ], []);

  const filtered = projects.filter(p => filter === 'Все' || p.cat === filter);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="portfolio-root">
      {/* ПРИНУДИТЕЛЬНОЕ ПОДКЛЮЧЕНИЕ ТЕХНОЛОГИЙ */}
      <link href="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css" rel="stylesheet" />

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;600&family=Playfair+Display:ital,wght@0,400;1,700&display=swap');

        :root {
          --bg-dark: #0a0a0c;
          --accent-pink: #ffb3d9;
          --glass-bg: rgba(255, 255, 255, 0.03);
          --glass-border: rgba(255, 255, 255, 0.1);
        }

        body {
          margin: 0;
          padding: 0;
          background-color: var(--bg-dark) !important;
          color: #e0e0e6 !important;
          font-family: 'Inter', sans-serif;
          -webkit-font-smoothing: antialiased;
        }

        /* ГЛАССМОРФИЗМ */
        .glass-nav {
          background: rgba(10, 10, 12, 0.7);
          backdrop-filter: blur(20px);
          -webkit-backdrop-filter: blur(20px);
          border-bottom: 1px solid var(--glass-border);
        }

        .glass-card {
          background: var(--glass-bg);
          backdrop-filter: blur(10px);
          border: 1px solid var(--glass-border);
          border-radius: 24px;
          transition: all 0.5s cubic-bezier(0.2, 1, 0.3, 1);
        }

        .glass-card:hover {
          border-color: var(--accent-pink);
          transform: translateY(-8px);
          background: rgba(255, 179, 217, 0.05);
        }

        /* ТИПОГРАФИКА */
        .hero-title {
          font-family: 'Playfair Display', serif;
          font-size: clamp(3rem, 10vw, 8rem);
          line-height: 0.9;
          letter-spacing: -0.04em;
        }

        .accent-text {
          color: var(--accent-pink);
          font-style: italic;
        }

        .nav-link {
          font-size: 10px;
          text-transform: uppercase;
          letter-spacing: 0.3em;
          opacity: 0.5;
          transition: opacity 0.3s;
        }

        .nav-link:hover { opacity: 1; color: var(--accent-pink); }

        /* КАТЕГОРИИ */
        .cat-btn {
          padding: 8px 20px;
          border-radius: 99px;
          font-size: 10px;
          text-transform: uppercase;
          letter-spacing: 0.1em;
          border: 1px solid var(--glass-border);
          background: rgba(255,255,255,0.03);
          transition: all 0.3s;
        }

        .cat-btn.active {
          background: var(--accent-pink);
          color: #000;
          border-color: var(--accent-pink);
        }

        /* АНИМАЦИИ */
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(30px); }
          to { opacity: 1; transform: translateY(0); }
        }

        .animate-up {
          animation: fadeUp 1s ease forwards;
        }
      `}</style>

      {/* НАВИГАЦИЯ */}
      <nav className={`fixed top-0 w-full z-50 transition-all glass-nav ${isScrolled ? 'py-4' : 'py-8'}`}>
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <div className="flex flex-col">
            <span className="text-xs font-bold tracking-widest" style={{color: 'var(--accent-pink)'}}>ALEXANDRA B.</span>
            <span className="text-[8px] opacity-30 uppercase tracking-[0.4em]">Design Edition</span>
          </div>

          <div className="hidden md:flex gap-12">
            <a href="#work" className="nav-link">Работы</a>
            <a href="#about" className="nav-link">Обо мне</a>
            <a href="https://t.me/renraie" className="nav-link">Контакт</a>
          </div>

          <button className="text-[10px] border border-white/20 px-6 py-2 rounded-full hover:bg-white hover:text-black transition-all uppercase tracking-widest">
            Brief
          </button>
        </div>
      </nav>

      {/* ГЛАВНЫЙ ЭКРАН */}
      <section className="min-h-screen flex flex-col justify-center px-6 pt-20">
        <div className="max-w-7xl mx-auto w-full">
          <h1 className="hero-title animate-up">
            Visual <br />
            <span className="accent-text">Aesthetics</span>
          </h1>
          <p className="mt-12 max-w-xl text-lg md:text-xl font-light opacity-50 leading-relaxed animate-up" style={{animationDelay: '0.2s'}}>
            Александра Благодатских. Специализируюсь на создании чистого, 
            функционального дизайна и визуальных систем.
          </p>
        </div>
      </section>

      {/* ФИЛЬТРЫ */}
      <div className="sticky top-24 z-40 py-6 px-6">
        <div className="max-w-7xl mx-auto flex flex-wrap gap-3">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`cat-btn ${filter === cat ? 'active' : ''}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* ГРИД ПРОЕКТОВ */}
      <main id="work" className="max-w-7xl mx-auto px-6 pb-40 pt-10">
